VALUES
  ('medical-tech-moex-08388', 'medical-tech', 'medical-tech-moex-106-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '關於後天免疫缺乏症候群（acquired immunodeficiency syndrome, AIDS）的敘述，下列何者正確？', '["AIDS病人容易得到中樞神經系統T細胞淋巴癌", "測量全血中CD4陽性細胞數可知道人類免疫缺乏病毒（HIV）感染後當時的疾病狀態", "AIDS病人的卡波西氏肉瘤（Kaposi''s sarcoma），主要與人類疱疹病毒第6型（human herpes virus-6, HHV-6）感染有關", "AIDS的定義為全血中CD4陽性細胞數小於500/µL"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:33+00:00", "source_pdf_sha1": "f67cef84ccb0", "answer_pdf_sha1": "86cfdf4d0e1c", "source_family": "moex-gov-tw", "moex": {"exam_code": "106100", "c": "308", "s": "11", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "106", "exam_name": "106年第二次專技人員高等考試醫師考試分階段考試（第一階段）、牙醫師藥師考試分階段考試、藥師、醫事檢驗師、醫事放射師、物理治療師、職能治療師...", "original_question_number": 67, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-08389', 'medical-tech', 'medical-tech-moex-106-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '關於全身性紅斑狼瘡（systemic lupus erythematosus, SLE）所造成病變的敘述，下列何者正確？', '["皮膚病變主要是因為自體抗體（autoantibodies）與表皮下的基底層（basement membrane）結合，再激發 T細胞過度反應所致", "環間膜增生性腎絲球腎炎（mesangial proliferative glomerulonephritis）主要是因為自體抗體 （autoantibodies）與腎絲球間質抗原結合，造成腎絲球內環間膜細胞（intraglomerular mesangial cells）增 生所致", "肝臟的病變主要是以煙管型纖維化（pipe-stem fibrosis）表現", "血球數目低下（cytopenia）主要是因為自體抗體（autoantibodies）引起的第二型免疫過度反應所致"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:33+00:00", "source_pdf_sha1": "f67cef84ccb0", "answer_pdf_sha1": "86cfdf4d0e1c", "source_family": "moex-gov-tw", "moex": {"exam_code": "106100", "c": "308", "s": "11", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "106", "exam_name": "106年第二次專技人員高等考試醫師考試分階段考試（第一階段）、牙醫師藥師考試分階段考試、藥師、醫事檢驗師、醫事放射師、物理治療師、職能治療師...", "original_question_number": 68, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-08390', 'medical-tech', 'medical-tech-moex-106-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '關於立得氏甲狀腺炎（Riedel thyroiditis）之敘述，下列何者正確？', '["甲狀腺呈現明顯纖維化", "甲狀腺呈現柔軟、可移動性腫塊", "血中很少出現抗甲狀腺抗體", "為最常見的甲狀腺炎"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:33+00:00", "source_pdf_sha1": "f67cef84ccb0", "answer_pdf_sha1": "86cfdf4d0e1c", "source_family": "moex-gov-tw", "moex": {"exam_code": "106100", "c": "308", "s": "11", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "106", "exam_name": "106年第二次專技人員高等考試醫師考試分階段考試（第一階段）、牙醫師藥師考試分階段考試、藥師、醫事檢驗師、醫事放射師、物理治療師、職能治療師...", "original_question_number": 69, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-08391', 'medical-tech', 'medical-tech-moex-106-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '關於布魯頓氏無γ球蛋白血症（Bruton agammaglobulinemia）的敘述，下列何者正確？', '["病人因為無法製造正常的BTK（Bruton tyrosine kinase）蛋白，導致B淋巴細胞發育停留在pre-B階段", "位於第10對染色體上的BTK（Bruton agammaglobulinemia tyrosine kinase）基因發生突變所致", "大多數病人在出生1個月內便因嚴重感染導致死亡", "因為容易遭受感染，淋巴結會出現明顯的淋巴濾泡（lymphoid follicle）形成"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:33+00:00", "source_pdf_sha1": "f67cef84ccb0", "answer_pdf_sha1": "86cfdf4d0e1c", "source_family": "moex-gov-tw", "moex": {"exam_code": "106100", "c": "308", "s": "11", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "106", "exam_name": "106年第二次專技人員高等考試醫師考試分階段考試（第一階段）、牙醫師藥師考試分階段考試、藥師、醫事檢驗師、醫事放射師、物理治療師、職能治療師...", "original_question_number": 70, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
